#include <algorithm>

// Optimized Partition using Median-of-Three pivot selection
int partition(std::vector<int>& arr, int low, int high) {
    int mid = low + (high - low) / 2;
    if (arr[mid] < arr[low]) std::swap(arr[mid], arr[low]);
    if (arr[high] < arr[low]) std::swap(arr[high], arr[low]);
    if (arr[mid] < arr[high]) std::swap(arr[mid], arr[high]);
    int pivot = arr[high], i = low;
    for (int j = low; j < high; ++j)
        if (arr[j] < pivot) std::swap(arr[i++], arr[j]);
    std::swap(arr[i], arr[high]);
    return i;
}

// Hybrid Quicksort with Tail-Recursion and small-partition optimization
void quicksort(std::vector<int>& arr, int low, int high) {
    while (low < high) {
        if (high - low < 16) {
            std::sort(arr.begin() + low, arr.begin() + high + 1);
            return;
        }
        int p = partition(arr, low, high);
        if (p - low < high - p) {
            quicksort(arr, low, p - 1);
            low = p + 1;
        } else {
            quicksort(arr, p + 1, high);
            high = p - 1;
        }
    }
}

void adaptive_sort(std::vector<int>& arr) {
    if (arr.size() > 1 && !std::is_sorted(arr.begin(), arr.end()))
        quicksort(arr, 0, static_cast<int>(arr.size()) - 1);
}

